import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"上海迪士尼乐园攻略2026 | iVoyageWiki","description":"上海迪士尼乐园游玩攻略，涵盖门票、项目推荐、餐饮住宿等完整指南","frontmatter":{"title":"上海迪士尼乐园攻略2026 | iVoyageWiki","description":"上海迪士尼乐园游玩攻略，涵盖门票、项目推荐、餐饮住宿等完整指南"},"headers":[],"relativePath":"destinations/中国/上海/迪士尼乐园.md","filePath":"destinations/中国/上海/迪士尼乐园.md","lastUpdated":null}'),o={name:"destinations/中国/上海/迪士尼乐园.md"};function n(l,a,h,d,s,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="迪士尼乐园" tabindex="-1">迪士尼乐园 <a class="header-anchor" href="#迪士尼乐园" aria-label="Permalink to &quot;迪士尼乐园&quot;">​</a></h1><h2 id="城市概览" tabindex="-1">城市概览 <a class="header-anchor" href="#城市概览" aria-label="Permalink to &quot;城市概览&quot;">​</a></h2><p>上海迪士尼乐园是中国内地首座迪士尼主题乐园，位于浦东新区，拥有七大主题园区，适合各年龄段游客。</p><h2 id="行前准备" tabindex="-1">行前准备 <a class="header-anchor" href="#行前准备" aria-label="Permalink to &quot;行前准备&quot;">​</a></h2><p>提前下载上海迪士尼官方APP查看排队时间，建议购买早享卡提前入园。穿着舒适，大部分时间在步行。</p><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><p>地铁11号线直达迪士尼站。自驾可导航至迪士尼停车场，收费约100元/天。</p><h2 id="必去景点" tabindex="-1">必去景点 <a class="header-anchor" href="#必去景点" aria-label="Permalink to &quot;必去景点&quot;">​</a></h2><p>翱翔·飞越地平线、创极速光轮、加勒比海盗—沉落宝藏之战、七个小矮人矿山车、抱抱龙冲天赛车。</p><h2 id="美食推荐" tabindex="-1">美食推荐 <a class="header-anchor" href="#美食推荐" aria-label="Permalink to &quot;美食推荐&quot;">​</a></h2><p>园区内推荐巴波萨烧烤的猪肋排饭、星露台餐厅的汉堡套餐。可带未开封的零食入园。</p><h2 id="购物指南" tabindex="-1">购物指南 <a class="header-anchor" href="#购物指南" aria-label="Permalink to &quot;购物指南&quot;">​</a></h2><p>M大街购物廊、迪士尼小镇有丰富的纪念品商店。限量商品需早起排队或抽签购买。</p><h2 id="行程规划" tabindex="-1">行程规划 <a class="header-anchor" href="#行程规划" aria-label="Permalink to &quot;行程规划&quot;">​</a></h2><p>一日游建议早8点前到门口排队，优先玩热门项目。两日游更轻松，可看完整场演出和烟花秀。</p><h2 id="避坑指南" tabindex="-1">避坑指南 <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;避坑指南&quot;">​</a></h2><p>工作日人最少，节假日和周末排队时间极长。雨天部分室外项目会暂停。</p>',17)])])}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
